import { readdir, stat } from "node:fs/promises";
import { basename, join, resolve } from "node:path";

import { inspectResultSchema, type InspectResult } from "./result-contracts";
import { pathExists, readTextFile } from "./fs-utils";

const ALLOWED_TECH_DESIGN_COMPANIONS = [
  "tech-design-cli-runtime.md",
  "tech-design-skill-process.md",
] as const;

interface StoryRecord {
  id: string;
  title: string;
  path: string;
  order: number;
}

async function pathIsDirectory(path: string): Promise<boolean> {
  try {
    return (await stat(path)).isDirectory();
  } catch {
    return false;
  }
}

function extractStoryTitle(content: string, fallback: string): string {
  const match = content.match(/^#\s+(.+)$/m);
  return match?.[1]?.trim() || fallback;
}

function storySortKey(fileName: string): [number, string] {
  const match = fileName.match(/^(\d+)-/);
  return [match ? Number(match[1]) : Number.MAX_SAFE_INTEGER, fileName];
}

async function readStoryInventory(storiesDir: string): Promise<StoryRecord[]> {
  const entries = await readdir(storiesDir, { withFileTypes: true });
  const fileNames = entries
    .filter((entry) => entry.isFile() && entry.name.endsWith(".md"))
    .map((entry) => entry.name)
    .filter((fileName) => fileName !== "coverage.md")
    .sort((left, right) => {
      const [leftPrefix, leftName] = storySortKey(left);
      const [rightPrefix, rightName] = storySortKey(right);
      if (leftPrefix !== rightPrefix) {
        return leftPrefix - rightPrefix;
      }
      return leftName.localeCompare(rightName);
    });

  const stories: StoryRecord[] = [];

  for (const [index, fileName] of fileNames.entries()) {
    const path = join(storiesDir, fileName);
    const content = await readTextFile(path);
    stories.push({
      id: basename(fileName, ".md"),
      title: extractStoryTitle(content, basename(fileName, ".md")),
      path,
      order: index + 1,
    });
  }

  return stories;
}

function resolveTechDesignArtifacts(entries: string[]): {
  techDesignShape: "two-file" | "four-file";
  companionPaths: string[];
  blockers: string[];
} {
  const companionFiles = entries
    .filter(
      (entry) =>
        entry.startsWith("tech-design-") &&
        entry.endsWith(".md") &&
        entry !== "tech-design.md"
    )
    .sort((left, right) => left.localeCompare(right));

  if (companionFiles.length === 0) {
    return {
      techDesignShape: "two-file",
      companionPaths: [],
      blockers: [],
    };
  }

  const allowed = [...ALLOWED_TECH_DESIGN_COMPANIONS].sort((left, right) =>
    left.localeCompare(right)
  );

  if (JSON.stringify(companionFiles) === JSON.stringify(allowed)) {
    return {
      techDesignShape: "four-file",
      companionPaths: companionFiles,
      blockers: [],
    };
  }

  return {
    techDesignShape: "two-file",
    companionPaths: [],
    blockers: [
      "Invalid tech-design companion layout: expected tech-design-cli-runtime.md and tech-design-skill-process.md for the four-file configuration",
    ],
  };
}

export async function inspectSpecPack(specPackRoot: string): Promise<InspectResult> {
  const resolvedRoot = resolve(specPackRoot);
  const epicPath = join(resolvedRoot, "epic.md");
  const techDesignPath = join(resolvedRoot, "tech-design.md");
  const testPlanPath = join(resolvedRoot, "test-plan.md");
  const storiesDir = join(resolvedRoot, "stories");
  const storiesFile = join(resolvedRoot, "stories.md");
  const blockers: string[] = [];
  const notes: string[] = [];

  if (!(await pathExists(epicPath))) {
    blockers.push("Missing required artifact: epic.md");
  }

  if (!(await pathExists(techDesignPath))) {
    blockers.push("Missing required artifact: tech-design.md");
  }

  if (!(await pathExists(testPlanPath))) {
    blockers.push("Missing required artifact: test-plan.md");
  }

  const storiesDirExists = await pathIsDirectory(storiesDir);
  if (!storiesDirExists && (await pathExists(storiesFile))) {
    blockers.push("Expected stories/ directory but found stories.md");
  } else if (!storiesDirExists) {
    blockers.push("Missing required artifact: stories/");
  }

  const rootEntries = await readdir(resolvedRoot);
  const techDesignArtifacts = resolveTechDesignArtifacts(rootEntries);
  blockers.push(...techDesignArtifacts.blockers);

  const stories = storiesDirExists ? await readStoryInventory(storiesDir) : [];
  const implInsertPath = join(
    resolvedRoot,
    "custom-story-impl-prompt-insert.md"
  );
  const verifierInsertPath = join(
    resolvedRoot,
    "custom-story-verifier-prompt-insert.md"
  );

  const result: InspectResult = {
    status: blockers.length > 0 ? "blocked" : "ready",
    specPackRoot: resolvedRoot,
    techDesignShape: techDesignArtifacts.techDesignShape,
    artifacts: {
      epicPath,
      techDesignPath,
      techDesignCompanionPaths: techDesignArtifacts.companionPaths.map((file) =>
        join(resolvedRoot, file)
      ),
      testPlanPath,
      storiesDir,
    },
    stories,
    inserts: {
      customStoryImplPromptInsert: (await pathExists(implInsertPath))
        ? "present"
        : "absent",
      customStoryVerifierPromptInsert: (await pathExists(verifierInsertPath))
        ? "present"
        : "absent",
    },
    blockers,
    notes,
  };

  return inspectResultSchema.parse(result);
}

import { defineCommand } from "citty";

import { nextArtifactPath, writeJsonArtifact } from "../core/artifact-writer";
import {
  cliResultEnvelopeSchema,
  createResultEnvelope,
  exitCodeForStatus,
  type CliArtifactRef,
  type CliError,
  type CliStatus,
  inspectResultSchema,
  type InspectResult,
} from "../core/result-contracts";
import { inspectSpecPack } from "../core/spec-pack";

interface OutputEnvelope {
  command: string;
  version: 1;
  status: CliStatus;
  outcome: string;
  result?: unknown;
  errors: CliError[];
  warnings: string[];
  artifacts: CliArtifactRef[];
  startedAt: string;
  finishedAt: string;
}

function renderHumanSummary(envelope: OutputEnvelope) {
  if (
    typeof envelope.result !== "object" ||
    envelope.result === null ||
    !("techDesignShape" in envelope.result)
  ) {
    return `inspect: ${envelope.outcome}`;
  }

  const result = envelope.result as InspectResult;
  const lines = [
    `inspect: ${envelope.outcome}`,
    `tech design: ${result.techDesignShape}`,
    `stories: ${result.stories.length}`,
    `impl insert: ${result.inserts.customStoryImplPromptInsert}`,
    `verifier insert: ${result.inserts.customStoryVerifierPromptInsert}`,
  ];

  if (result.blockers.length > 0) {
    lines.push(...result.blockers.map((blocker) => `blocker: ${blocker}`));
  }

  return lines.join("\n");
}

function emitOutput(params: {
  envelope: OutputEnvelope;
  json: boolean;
}) {
  if (params.json) {
    console.log(JSON.stringify(params.envelope));
    return;
  }

  console.log(renderHumanSummary(params.envelope));
}

export default defineCommand({
  meta: {
    name: "inspect",
    description: "Resolve the spec-pack layout, tech-design shape, and public insert files.",
  },
  args: {
    "spec-pack-root": {
      type: "string",
      description: "Absolute or relative path to the spec-pack root",
      required: true,
    },
    json: {
      type: "boolean",
      description: "Emit the structured JSON envelope on stdout",
    },
  },
  async run({ args }) {
    const startedAt = new Date().toISOString();

    try {
      const inspectResult = await inspectSpecPack(args["spec-pack-root"]);
      const artifactPath = await nextArtifactPath(
        inspectResult.specPackRoot,
        "inspect"
      );
      const envelope = cliResultEnvelopeSchema(inspectResultSchema).parse(
        createResultEnvelope({
          command: "inspect",
          outcome: inspectResult.status,
          result: inspectResult,
          errors:
            inspectResult.status === "blocked"
              ? [
                  {
                    code: "INVALID_SPEC_PACK",
                    message: "Spec-pack inspection failed",
                  },
                ]
              : [],
          artifacts: [
            {
              kind: "result-envelope",
              path: artifactPath,
            },
          ],
          startedAt,
          finishedAt: new Date().toISOString(),
        })
      );

      await writeJsonArtifact(artifactPath, envelope);
      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status);
    } catch (error) {
      const envelope: OutputEnvelope = createResultEnvelope({
        command: "inspect",
        outcome: "error",
        errors: [
          {
            code: "UNEXPECTED_ERROR",
            message: error instanceof Error ? error.message : String(error),
          },
        ],
        startedAt,
        finishedAt: new Date().toISOString(),
      });

      emitOutput({
        envelope,
        json: Boolean(args.json),
      });
      process.exitCode = exitCodeForStatus(envelope.status);
    }
  },
});

import { join, resolve } from "node:path";

import { pathExists, readTextFile, writeTextFile } from "./fs-utils";

export const TEAM_IMPL_LOG_FILE_NAME = "team-impl-log.md";

export interface EnsureTeamImplLogInput {
  specPackRoot: string;
  storyIds: string[];
}

export interface EnsureTeamImplLogResult {
  created: boolean;
  path: string;
  content: string;
}

export function renderTeamImplLogTemplate(input: EnsureTeamImplLogInput): string {
  const specPackRoot = resolve(input.specPackRoot);
  const storyLines =
    input.storyIds.length === 0
      ? "- none yet"
      : input.storyIds.map((storyId) => `- ${storyId}`).join("\n");

  return [
    "# Team Implementation Log",
    "",
    "## Run Overview",
    "- State: SETUP",
    `- Spec Pack Root: ${specPackRoot}`,
    "- Current Story: not-started",
    "- Current Phase: inspect",
    "",
    "## Run Configuration",
    "- Primary Harness: claude-code",
    "- Story Implementor: pending",
    "- Quick Fixer: pending",
    "- Story Verifier 1: pending",
    "- Story Verifier 2: pending",
    "- Self Review Passes: pending",
    "- Degraded Diversity: pending",
    "",
    "## Verification Gates",
    "- Story Gate: pending",
    "- Epic Gate: pending",
    "- Gate Discovery Source: pending",
    "",
    "## Story Sequence",
    storyLines,
    "",
    "## Current Continuation Handles",
    "- none",
    "",
    "## Story Receipts",
    "- none yet",
    "",
    "## Cumulative Baselines",
    "- Baseline Before Current Story: pending",
    "- Expected After Current Story: pending",
    "- Latest Actual Total: pending",
    "",
    "## Cleanup / Epic Verification",
    "- Cleanup Artifact: pending",
    "- Cleanup Status: not-started",
    "- Epic Verification Status: not-started",
    "",
    "## Open Risks / Accepted Risks",
    "- none",
    "",
  ].join("\n");
}

export async function ensureTeamImplLog(
  input: EnsureTeamImplLogInput
): Promise<EnsureTeamImplLogResult> {
  const path = join(resolve(input.specPackRoot), TEAM_IMPL_LOG_FILE_NAME);

  if (await pathExists(path)) {
    return {
      created: false,
      path,
      content: await readTextFile(path),
    };
  }

  const content = renderTeamImplLogTemplate(input);
  await writeTextFile(path, content);

  return {
    created: true,
    path,
    content,
  };
}
